#!/usr/bin/env bash
set -e
C="\033[0;36m"; G="\033[0;32m"; N="\033[0m"
echo -e "${C}Ninja Language Runner v2 Installer${N}"
mkdir -p css js data

echo "  writing index.html"
echo "" | base64 -d > index.html

echo "  writing css/style.css"
echo "" | base64 -d > css/style.css

echo "  writing data/words.js"
echo "" | base64 -d > data/words.js

echo "  writing js/memory.js"
echo "" | base64 -d > js/memory.js

echo "  writing js/audio.js"
echo "" | base64 -d > js/audio.js

echo "  writing js/charts.js"
echo "" | base64 -d > js/charts.js

echo "  writing js/game.js"
true > js/game.js
echo "" | base64 -d >> js/game.js
echo "" | base64 -d >> js/game.js

echo "  writing js/ui.js"
echo "" | base64 -d > js/ui.js

echo "  writing js/app.js"
echo "" | base64 -d > js/app.js

echo ""
echo -e "${G}All files installed!${N}"
echo "Push: git add -A && git commit -m v2 && git push"
echo "Local test: python -m http.server 8080"